diff --git a/src/Carbon/Traits/Timestamp.php b/src/Carbon/Traits/Timestamp.php
index dab448d..c4c1972 100644
--- a/src/Carbon/Traits/Timestamp.php
+++ b/src/Carbon/Traits/Timestamp.php
@@ -39,9 +39,35 @@ trait Timestamp
+        if (\is_string($timestamp)) {
+            $sign = str_starts_with($timestamp, '-') ? '-' : '';
+            $timestamp = ltrim($timestamp, '+-');
+            if (str_contains($timestamp, '.')) {
+                [$seconds, $micro] = explode('.', $timestamp, 2);
+                $micro = str_pad(substr($micro, 0, 6), 6, '0');
+            } else {
+                $seconds = $timestamp;
+                $micro = '000000';
+            }
+            $instance = static::rawCreateFromFormat('U u', "$sign$seconds $micro");
+            if ($sign === '-') {
+                $instance = static::rawCreateFromFormat('U.u', $sign.$seconds.'.'.$micro);
+            }
+            return $instance;
+        }
